import{_ as e,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Приложение | agent-app-factory","description":"Справочные документы: полный список CLI-команд, подробное описание структуры каталогов проекта, требования к коду и описание технического стека.","frontmatter":{"title":"Приложение | agent-app-factory","sidebarTitle":"Приложение","subtitle":"Приложение","description":"Справочные документы: полный список CLI-команд, подробное описание структуры каталогов проекта, требования к коду и описание технического стека.","order":210},"headers":[],"relativePath":"ru/hyz1992/agent-app-factory/appendix/index.md","filePath":"ru/hyz1992/agent-app-factory/appendix/index.md"}'),o={name:"ru/hyz1992/agent-app-factory/appendix/index.md"};function c(l,a,d,n,s,h){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="приложение" tabindex="-1">Приложение <a class="header-anchor" href="#приложение" aria-label="Permalink to &quot;Приложение&quot;">​</a></h1><p>Этот раздел содержит справочные документы и дополнительные материалы, которые помогут вам глубже понять технические детали AI App Factory.</p><h2 id="навигация-по-подразделам" tabindex="-1">Навигация по подразделам <a class="header-anchor" href="#навигация-по-подразделам" aria-label="Permalink to &quot;Навигация по подразделам&quot;">​</a></h2><h3 id="справочник-по-cli-командам" tabindex="-1"><a href="./../cli-commands/">Справочник по CLI-командам</a> <a class="header-anchor" href="#справочник-по-cli-командам" aria-label="Permalink to &quot;[Справочник по CLI-командам](../cli-commands/)&quot;">​</a></h3><p>Полный список CLI-команд с описанием параметров и примерами использования, включая команды <code>init</code>, <code>run</code>, <code>continue</code>, <code>status</code>, <code>list</code> и <code>reset</code>.</p><h3 id="подробная-структура-каталогов" tabindex="-1"><a href="./../directory-structure/">Подробная структура каталогов</a> <a class="header-anchor" href="#подробная-структура-каталогов" aria-label="Permalink to &quot;[Подробная структура каталогов](../directory-structure/)&quot;">​</a></h3><p>Узнайте полную структуру каталогов проекта Factory и назначение каждого файла, включая назначение основных каталогов <code>agents/</code>, <code>skills/</code>, <code>cli/</code> и других.</p><h3 id="стандарты-кода" tabindex="-1"><a href="./../code-standards/">Стандарты кода</a> <a class="header-anchor" href="#стандарты-кода" aria-label="Permalink to &quot;[Стандарты кода](../code-standards/)&quot;">​</a></h3><p>Узнайте о стандартах кодирования TypeScript, структуре файлов, требованиях к комментариям и стандартах для сообщений коммитов, которым должен соответствовать генерируемый код.</p><h3 id="подробное-описание-технического-стека" tabindex="-1"><a href="./../tech-stack/">Подробное описание технического стека</a> <a class="header-anchor" href="#подробное-описание-технического-стека" aria-label="Permalink to &quot;[Подробное описание технического стека](../tech-stack/)&quot;">​</a></h3><p>Узнайте о техническом стеке, используемом в генерируемых приложениях: Node.js + Express + Prisma + React Native, а также о причинах выбора технологий для каждой части.</p><h2 id="рекомендации-по-пути-обучения" tabindex="-1">Рекомендации по пути обучения <a class="header-anchor" href="#рекомендации-по-пути-обучения" aria-label="Permalink to &quot;Рекомендации по пути обучения&quot;">​</a></h2><p>Документы этого раздела являются <strong>справочными материалами</strong>, их не обязательно читать по порядку. Рекомендуется обращаться к соответствующим разделам по мере необходимости при изучении основного руководства:</p><ul><li>При изучении <a href="./../../start/installation/">Установки и настройки</a> можно обратиться к <a href="./../cli-commands/">Справочнику по CLI-командам</a></li><li>При изучении <a href="./../../start/init-project/">Инициализации проекта Factory</a> можно обратиться к <a href="./../directory-structure/">Подробной структуре каталогов</a></li><li>При изучении различных этапов конвейера можно обратиться к <a href="./../tech-stack/">Подробному описанию технического стека</a></li><li>Когда нужно понять стандарты качества генерируемого кода, можно обратиться к <a href="./../code-standards/">Стандартам кода</a></li></ul><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><p>Нет предварительных требований. Для лучшего понимания содержимого этого раздела рекомендуется сначала выполнить следующие руководства:</p><ul><li>✅ <a href="./../../start/getting-started/">Быстрый старт: от идеи до приложения</a></li><li>✅ <a href="./../../start/installation/">Установка и настройка</a></li><li>✅ <a href="./../../start/init-project/">Инициализация проекта Factory</a></li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения изучения основного руководства вы можете продолжить изучение:</p><ul><li>Просмотрите <a href="./../../changelog/release-notes/">Журнал изменений</a> для ознакомления с новыми функциями</li><li>Ознакомьтесь с <a href="./../../faq/best-practices/">Лучшими практиками</a> для повышения эффективности использования</li><li>Изучите <a href="./../../advanced/">Продвинутые темы</a> для понимания принципов проектирования системы</li></ul>',20)])])}const f=e(o,[["render",c]]);export{u as __pageData,f as default};
